import { Component, OnInit, OnDestroy } from '@angular/core';
import { CommonModule } from '@angular/common';
import { FormsModule } from '@angular/forms';
import { trigger, transition, style, animate } from '@angular/animations';
import { ParkaddaService } from '../../../../services/parkadda.service';
import { Subject } from 'rxjs';
import { takeUntil, debounceTime } from 'rxjs/operators';

interface TransactionReport {
  id: number;
  transactionId: string;
  amount: number;
  transactionType: string;
  vehicleNumber: string;
  parkingLocation: string;
  transactionDate: string;
  status: string;
  paymentMethod: string;
  reference: string;
}

interface TransactionFilter {
  parkingId: number | null;
  fromDate: string;
  toDate: string;
  pageSize: number;
  currentPage: number;
}

@Component({
  selector: 'app-transaction-reports',
  standalone: true,
  imports: [CommonModule, FormsModule],
  templateUrl: './transaction-reports.component.html',
  styleUrls: ['./transaction-reports.component.scss'],
  animations: [
    trigger('fadeInOut', [
      transition(':enter', [
        style({ opacity: 0, transform: 'translateY(-10px)' }),
        animate('300ms ease-in', style({ opacity: 1, transform: 'translateY(0)' }))
      ]),
      transition(':leave', [
        animate('300ms ease-out', style({ opacity: 0, transform: 'translateY(-10px)' }))
      ])
    ]),
    trigger('slideIn', [
      transition(':enter', [
        style({ transform: 'translateX(400px)', opacity: 0 }),
        animate('300ms ease-out', style({ transform: 'translateX(0)', opacity: 1 }))
      ])
    ])
  ]
})
export class TransactionReportsComponent implements OnInit, OnDestroy {
  cashTransactions: TransactionReport[] = [];
  cardTransactions: TransactionReport[] = [];
  upiTransactions: TransactionReport[] = [];
  fastagTransactions: TransactionReport[] = [];
  paymentGatewayTransactions: TransactionReport[] = [];
  filteredTransactions: TransactionReport[] = [];

  loading = false;
  selectedTransactionType = 'cash'; // 'cash', 'card', 'upi', 'fastag', 'gateway', 'all'
  searchTerm = '';
  selectedTransaction: TransactionReport | null = null;
  showDetailsModal = false;
  toasts: Array<{ message: string; type: string }> = [];

  parkings: Array<{ id: number; name: string }> = [];
  currentPage = 1;
  pageSize = 10;
  totalCount = 0;
  totalPages = 1;
  totalAmount = 0;

  filter: TransactionFilter = {
    parkingId: null,
    fromDate: this.getFormattedDate(new Date(new Date().setDate(new Date().getDate() - 30))),
    toDate: this.getFormattedDate(new Date()),
    pageSize: 10,
    currentPage: 1
  };

  private destroy$ = new Subject<void>();
  private searchSubject$ = new Subject<string>();

  constructor(private parkaddaService: ParkaddaService) {}

  ngOnInit() {
    this.loadParkings();
    this.loadTransactions();

    this.searchSubject$
      .pipe(
        debounceTime(300),
        takeUntil(this.destroy$)
      )
      .subscribe(() => {
        this.filterTransactions();
      });
  }

  ngOnDestroy() {
    this.destroy$.next();
    this.destroy$.complete();
  }

  loadParkings() {
    this.parkaddaService.getParkingList()
      .pipe(takeUntil(this.destroy$))
      .subscribe({
        next: (response: any) => {
          const parkingData = response.data || [];
          this.parkings = parkingData.map((p: any) => ({
            id: p.parking_table_id || p.id,
            name: p.parking_name || p.name
          }));
          if (this.parkings.length > 0) {
            this.filter.parkingId = (response.data?.[0]?.parking_table_id || response.data?.[0]?.id) as number;
          }
        },
        error: (error: any) => {
          console.error('Error loading parkings:', error);
          this.showToast('Error loading parkings', 'error');
        }
      });
  }

  loadTransactions() {
    if (!this.filter.parkingId) {
      this.showToast('Please select a parking location', 'warning');
      return;
    }

    this.loading = true;
    const params = {
      page: this.filter.currentPage,
      page_size: this.filter.pageSize,
      parking_table_id: this.filter.parkingId,
      from_date_filter: this.filter.fromDate,
      to_date_filter: this.filter.toDate
    };

    // Load all transaction types
    Promise.all([
      this.parkaddaService.getCashTransactions(params).toPromise(),
      this.parkaddaService.getCardTransactions(params).toPromise(),
      this.parkaddaService.getUPITransactions(params).toPromise(),
      this.parkaddaService.getFastagTransactions(params).toPromise(),
      this.parkaddaService.getPaymentGatewayTransactions(params).toPromise()
    ])
      .then(([cashRes, cardRes, upiRes, fastagRes, gatewayRes]: any[]) => {
        this.cashTransactions = cashRes?.data?.results || [];
        this.cardTransactions = cardRes?.data?.results || [];
        this.upiTransactions = upiRes?.data?.results || [];
        this.fastagTransactions = fastagRes?.data?.results || [];
        this.paymentGatewayTransactions = gatewayRes?.data?.results || [];

        this.updateDisplayedTransactions();
        this.totalCount = cashRes?.data?.total_count || 0;
        this.totalPages = Math.ceil(this.totalCount / this.filter.pageSize);
        this.calculateTotalAmount();
        this.loading = false;
      })
      .catch((error) => {
        console.error('Error loading transactions:', error);
        this.showToast('Error loading transactions', 'error');
        this.loading = false;
      });
  }

  updateDisplayedTransactions() {
    let transactions: TransactionReport[] = [];
    switch (this.selectedTransactionType) {
      case 'cash':
        transactions = this.cashTransactions;
        break;
      case 'card':
        transactions = this.cardTransactions;
        break;
      case 'upi':
        transactions = this.upiTransactions;
        break;
      case 'fastag':
        transactions = this.fastagTransactions;
        break;
      case 'gateway':
        transactions = this.paymentGatewayTransactions;
        break;
      case 'all':
        transactions = [
          ...this.cashTransactions,
          ...this.cardTransactions,
          ...this.upiTransactions,
          ...this.fastagTransactions,
          ...this.paymentGatewayTransactions
        ];
        break;
      default:
        transactions = this.cashTransactions;
    }
    this.filteredTransactions = transactions;
    this.filterTransactions();
  }

  onTransactionTypeChange() {
    this.currentPage = 1;
    this.updateDisplayedTransactions();
  }

  onFilterChange() {
    this.currentPage = 1;
    this.loadTransactions();
  }

  onSearchChange() {
    this.searchSubject$.next(this.searchTerm);
  }

  filterTransactions() {
    this.filteredTransactions = this.filteredTransactions.filter(tx => {
      return !this.searchTerm ||
        tx.transactionId.toLowerCase().includes(this.searchTerm.toLowerCase()) ||
        tx.vehicleNumber.toLowerCase().includes(this.searchTerm.toLowerCase()) ||
        tx.parkingLocation.toLowerCase().includes(this.searchTerm.toLowerCase()) ||
        tx.reference.toLowerCase().includes(this.searchTerm.toLowerCase());
    });
  }

  calculateTotalAmount() {
    this.totalAmount = this.filteredTransactions.reduce((sum, tx) => sum + tx.amount, 0);
  }

  viewDetails(transaction: TransactionReport) {
    this.selectedTransaction = transaction;
    this.showDetailsModal = true;
  }

  closeDetailsModal() {
    this.showDetailsModal = false;
    this.selectedTransaction = null;
  }

  exportToCSV() {
    if (this.filteredTransactions.length === 0) {
      this.showToast('No data to export', 'warning');
      return;
    }

    const headers = ['Transaction ID', 'Amount', 'Type', 'Vehicle Number', 'Location', 'Date', 'Status', 'Payment Method'];
    const rows = this.filteredTransactions.map(tx => [
      tx.transactionId,
      tx.amount,
      tx.transactionType,
      tx.vehicleNumber,
      tx.parkingLocation,
      tx.transactionDate,
      tx.status,
      tx.paymentMethod
    ]);

    let csvContent = headers.join(',') + '\n';
    rows.forEach(row => {
      csvContent += row.map(cell => `"${cell}"`).join(',') + '\n';
    });

    const blob = new Blob([csvContent], { type: 'text/csv' });
    const url = window.URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `transaction-reports-${new Date().getTime()}.csv`;
    a.click();
    window.URL.revokeObjectURL(url);

    this.showToast('Report exported successfully', 'success');
  }

  nextPage() {
    if (this.currentPage < this.totalPages) {
      this.currentPage++;
      this.filter.currentPage = this.currentPage;
      this.loadTransactions();
    }
  }

  previousPage() {
    if (this.currentPage > 1) {
      this.currentPage--;
      this.filter.currentPage = this.currentPage;
      this.loadTransactions();
    }
  }

  private showToast(message: string, type: string) {
    this.toasts.push({ message, type });
    setTimeout(() => {
      this.toasts.shift();
    }, 3000);
  }

  getToastIcon(type: string): string {
    switch (type) {
      case 'success':
        return 'fa-check-circle';
      case 'error':
        return 'fa-exclamation-circle';
      case 'warning':
        return 'fa-exclamation-triangle';
      case 'info':
        return 'fa-info-circle';
      default:
        return 'fa-info-circle';
    }
  }

  getStatusClass(status: string): string {
    switch (status.toLowerCase()) {
      case 'success':
        return 'status-success';
      case 'pending':
        return 'status-pending';
      case 'failed':
        return 'status-failed';
      default:
        return 'status-default';
    }
  }

  private getFormattedDate(date: Date): string {
    const year = date.getFullYear();
    const month = String(date.getMonth() + 1).padStart(2, '0');
    const day = String(date.getDate()).padStart(2, '0');
    return `${year}-${month}-${day}`;
  }
}
